import { useState, useEffect } from 'react';
import { patientAPI } from '../../utils/api';
import { useApp } from '../../context/AppContext';
import { Link } from 'react-router-dom';
import toast from 'react-hot-toast';

export default function SymptomChecker() {
  const { patientId } = useApp();
  const [allSymptoms, setAllSymptoms] = useState([]);
  const [selected, setSelected] = useState([]);
  const [search, setSearch] = useState('');
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [expanded, setExpanded] = useState(0);

  useEffect(() => {
    patientAPI.getSymptoms().then(r => setAllSymptoms(r.data)).catch(() => {});
  }, []);

  const filtered = allSymptoms.filter(s =>
    s.name.toLowerCase().includes(search.toLowerCase()) && !selected.includes(s.name)
  );

  const toggleSymptom = (name) => {
    setSelected(prev =>
      prev.includes(name) ? prev.filter(s => s !== name) : [...prev, name]
    );
  };

  const handlePredict = async () => {
    if (selected.length === 0) { toast.error('Please select at least one symptom'); return; }
    setLoading(true);
    setResults(null);
    try {
      const res = await patientAPI.predict({ symptoms: selected, patient_id: patientId });
      setResults(res.data.results);
      if (res.data.results.length === 0) toast('No matching diseases found. Try adding more symptoms.', { icon: 'ℹ️' });
    } catch { toast.error('Prediction failed. Please try again.'); }
    finally { setLoading(false); }
  };

  const SEVERITY_COLOR = { Mild: 'badge-mild', Moderate: 'badge-moderate', Severe: 'badge-severe' };

  return (
    <div className="animate-fade">
      <div style={{ marginBottom: 24 }}>
        <h1 style={{ fontFamily: 'var(--font-display)', fontSize: 28, color: 'var(--text)', marginBottom: 6 }}>🔍 Symptom Checker</h1>
        <p style={{ color: 'var(--text-muted)' }}>Select your symptoms and we'll predict possible conditions using AI + rule-based analysis</p>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 24 }}>
        {/* LEFT: Symptom Selection */}
        <div>
          <div className="card" style={{ marginBottom: 16 }}>
            <div className="card-header"><h2>Select Symptoms</h2></div>
            <div className="card-body">
              <div className="form-group">
                <input
                  className="form-control"
                  placeholder="🔎 Search symptoms..."
                  value={search}
                  onChange={e => setSearch(e.target.value)}
                />
              </div>

              {/* Selected */}
              {selected.length > 0 && (
                <div style={{ marginBottom: 16 }}>
                  <div className="form-label" style={{ marginBottom: 8 }}>Selected ({selected.length})</div>
                  <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
                    {selected.map(s => (
                      <span key={s} className="symptom-tag selected">
                        {s}
                        <button className="symptom-tag-remove" onClick={() => toggleSymptom(s)}>×</button>
                      </span>
                    ))}
                  </div>
                </div>
              )}

              {/* All */}
              <div className="form-label" style={{ marginBottom: 8 }}>
                {search ? `Results for "${search}"` : 'All Symptoms'}
              </div>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8, maxHeight: 260, overflowY: 'auto', padding: '4px 0' }}>
                {filtered.map(s => (
                  <span key={s.id} className="symptom-tag" onClick={() => toggleSymptom(s.name)}>
                    + {s.name}
                  </span>
                ))}
                {filtered.length === 0 && <p style={{ color: 'var(--text-muted)', fontSize: 13 }}>No symptoms found</p>}
              </div>
            </div>
          </div>

          <button
            className="btn btn-primary btn-block btn-lg"
            onClick={handlePredict}
            disabled={loading || selected.length === 0}
          >
            {loading ? '⏳ Analyzing...' : `🧠 Analyze ${selected.length} Symptom${selected.length !== 1 ? 's' : ''}`}
          </button>

          {selected.length > 0 && (
            <button className="btn btn-outline btn-block" style={{ marginTop: 8 }} onClick={() => { setSelected([]); setResults(null); }}>
              Clear All
            </button>
          )}
        </div>

        {/* RIGHT: Results */}
        <div>
          {loading && (
            <div className="card">
              <div className="card-body" style={{ textAlign: 'center', padding: 48 }}>
                <div className="spinner" style={{ margin: '0 auto 16px' }} />
                <p style={{ color: 'var(--text-muted)' }}>Running AI + rule-based analysis...</p>
              </div>
            </div>
          )}

          {results && results.length === 0 && (
            <div className="card">
              <div className="empty-state">
                <div className="empty-icon">🤔</div>
                <h3>No matches found</h3>
                <p>Try adding more symptoms for better results</p>
              </div>
            </div>
          )}

          {results && results.length > 0 && (
            <div className="animate-slide">
              <p style={{ fontSize: 13, color: 'var(--text-muted)', marginBottom: 12 }}>
                ⚠️ This is for informational purposes only. Please consult a doctor for diagnosis.
              </p>
              {results.map((r, i) => (
                <div key={i} className="prediction-card">
                  <div className="prediction-header" onClick={() => setExpanded(expanded === i ? -1 : i)}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                      <div style={{
                        width: 36, height: 36, borderRadius: '50%',
                        background: i === 0 ? 'var(--primary)' : i === 1 ? 'var(--accent)' : 'var(--border)',
                        color: i < 2 ? 'white' : 'var(--text-muted)',
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        fontWeight: 700, fontSize: 14
                      }}>#{i + 1}</div>
                      <div>
                        <div style={{ fontWeight: 600, fontSize: 15 }}>{r.disease.name}</div>
                        <div style={{ fontSize: 12, color: 'var(--text-muted)', marginTop: 2 }}>
                          {r.disease.specialization} · {r.method}
                        </div>
                      </div>
                    </div>
                    <div style={{ textAlign: 'right' }}>
                      <div style={{ fontWeight: 700, fontSize: 18, color: 'var(--primary)' }}>{r.confidence}%</div>
                      <span className={`badge ${SEVERITY_COLOR[r.disease.severity]}`}>{r.disease.severity}</span>
                    </div>
                  </div>

                  <div className="confidence-bar" style={{ margin: '0 20px 0' }}>
                    <div className="confidence-fill" style={{ width: `${r.confidence}%` }} />
                  </div>

                  {expanded === i && (
                    <div className="prediction-body animate-fade">
                      <p style={{ fontSize: 14, color: 'var(--text-muted)', marginBottom: 16 }}>{r.disease.description}</p>

                      {r.medicines.length > 0 && (
                        <div style={{ marginBottom: 16 }}>
                          <div style={{ fontWeight: 600, fontSize: 14, marginBottom: 10 }}>💊 Suggested Medicines</div>
                          {r.medicines.map((m, j) => (
                            <div key={j} style={{ background: 'var(--bg)', borderRadius: 8, padding: '10px 14px', marginBottom: 8 }}>
                              <div style={{ fontWeight: 600, fontSize: 13 }}>{m.name} <span style={{ fontWeight: 400, color: 'var(--text-muted)' }}>({m.type})</span></div>
                              <div style={{ fontSize: 12, color: 'var(--text-muted)', marginTop: 2 }}>📋 {m.dosage}</div>
                            </div>
                          ))}
                        </div>
                      )}

                      {r.precautions.length > 0 && (
                        <div style={{ marginBottom: 16 }}>
                          <div style={{ fontWeight: 600, fontSize: 14, marginBottom: 10 }}>🛡️ Precautions</div>
                          {r.precautions.map((p, j) => (
                            <div key={j} style={{ display: 'flex', gap: 8, marginBottom: 6, fontSize: 13 }}>
                              <span>•</span><span>{p}</span>
                            </div>
                          ))}
                        </div>
                      )}

                      <Link
                        to={`/patient/doctors?specialization=${encodeURIComponent(r.disease.specialization || '')}`}
                        className="btn btn-primary btn-sm"
                      >
                        Find {r.disease.specialization} →
                      </Link>
                    </div>
                  )}

                  {expanded !== i && (
                    <div style={{ padding: '8px 20px 12px', fontSize: 12, color: 'var(--primary)', cursor: 'pointer' }}
                      onClick={() => setExpanded(i)}>
                      Show details ↓
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}

          {!results && !loading && (
            <div className="card">
              <div className="empty-state">
                <div className="empty-icon">🧬</div>
                <h3>Select your symptoms</h3>
                <p>Choose symptoms from the left panel and click Analyze</p>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
